<?php

/**
 * ApiContentTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class ApiContentTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return ApiContentTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('ApiContent');
    }
	//return api use types
	public function getApiuses()
	{
		return ["register" => "Register plan", "post_invoice" => "Post invoice","cancel_invoice" => "Cancel invoice","login" => "Login", "get_zone" => "Get Zones", "get_services" => "Get services"];
	}
	public function getApiservices($county_code)
	{
		error_log('-------county_code-----'.$county_code);
		$api=new ApiCalls();
		$zones=$api->getZones($county_code);
		foreach($zones as $zone){
			//Update zones table
			$q=Doctrine_Query::create()
				->from('Zones z')
				->where('z.zone_id =?',$zone['id']);
			$zone_rec=$q->fetchOne();
			error_log('------------Zone-----'.$zone['name']);
			if($zone_rec){
				//check for changes
				if(strcmp($zone_rec->getName(),$zone['name']) !== 0){
					//update
					$zone_rec->setName($zone['name']);
				}
				if(strcmp($zone_rec->getSubCounty(),strval($zone['subCountyId'])) !== 0){
					//update
					$zone_rec->setSubCounty($zone['subCountyId']);
				}
				$zone_rec->save();
			}else{
				//create zone
				$zone_rec=new Zones();
				$zone_rec->setZoneId($zone['id']);
				$zone_rec->setName($zone['name']);
				$zone_rec->setSubCounty($zone['subCountyId']);
				$zone_rec->save();
			}
			//use zone to create code/services
			$services_zones=$api->getServices($county_code,$zone['id']);
			foreach($services_zones as $service){
				error_log('-------service------'.$service['name']);
				//Update fee code
				$q=Doctrine_Query::create()
					->from('FeeCode f')
					->innerJoin('f.Zones z')
					->where('f.service_id =? and z.zone_id =?',array($service['id'],$zone['id']));
				$code=$q->fetchOne();
				if($code){
					//check for changes
					if(strcmp($code->getServiceName(),$service['name']) !== 0){
						//update
						$code->setServiceName($service['name']);
					}
					if($code->getFixed() !== intval($service['hasFixedCost'])){
						//update
						$code->setFixed(intval($service['hasFixedCost']));
					}
					if($code->getAmount() !== floatval($service['amount'])){
						//update
						$code->setAmount(floatval($service['amount']));
					}
					$code->save();
				}else{
					//create one
					$code=new FeeCode();
					$code->setServiceId($service['id']);
					$code->setServiceName($service['name']);
					$code->setFixed(intval($service['hasFixedCost']));
					$code->setAmount(floatval($service['amount']));
					$code->setZone($zone_rec->getId());
					$code->save();
				}
			}
			
		}
	}
	//return api use diff
	public function getApiusesdiff()
	{
		return ["" => "","individual" => "individual","institution" => "institution"];
	}
}